import { useState } from 'react';
import { SquarePen, Trash2, PanelLeftClose, PanelLeft, MessageSquare } from 'lucide-react';
import { Dot } from './ds';

export default function ChatSidebar({
  conversations, activeId, onSelect, onNewChat, onDelete,
  collapsed, onToggle, health,
}) {
  const [hoverId, setHoverId] = useState(null);

  if (collapsed) {
    return (
      <div style={{
        width: 0, overflow: 'hidden',
        transition: 'width 0.2s ease',
      }} />
    );
  }

  return (
    <div style={{
      width: 260, minWidth: 260,
      background: 'var(--sidebar-bg)',
      display: 'flex', flexDirection: 'column',
      transition: 'width 0.2s ease',
      borderRight: '1px solid var(--sidebar-border)',
    }}>

      {/* Top bar */}
      <div style={{
        padding: '12px 12px 8px',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      }}>
        <button
          onClick={onToggle}
          style={{
            background: 'none', border: 'none', cursor: 'pointer',
            color: 'var(--sidebar-text-muted)', padding: 6, borderRadius: 6,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}
          title="Close sidebar"
        >
          <PanelLeftClose size={18} strokeWidth={1.8} />
        </button>
        <button
          onClick={onNewChat}
          style={{
            background: 'none', border: 'none', cursor: 'pointer',
            color: 'var(--sidebar-text-muted)', padding: 6, borderRadius: 6,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}
          title="New chat"
        >
          <SquarePen size={18} strokeWidth={1.8} />
        </button>
      </div>

      {/* Conversation list */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '4px 8px' }}>
        {conversations.length === 0 && (
          <p style={{
            color: 'var(--sidebar-text-muted)', fontSize: 13,
            textAlign: 'center', padding: '32px 12px', lineHeight: 1.6,
          }}>
            No conversations yet
          </p>
        )}
        {conversations.map(conv => {
          const isActive = conv.id === activeId;
          const isHover = conv.id === hoverId;
          return (
            <div
              key={conv.id}
              onClick={() => onSelect(conv.id)}
              onMouseEnter={() => setHoverId(conv.id)}
              onMouseLeave={() => setHoverId(null)}
              style={{
                padding: '10px 10px',
                borderRadius: 8,
                cursor: 'pointer',
                background: isActive ? 'var(--sidebar-active)' : isHover ? 'var(--sidebar-hover)' : 'transparent',
                display: 'flex', alignItems: 'center', gap: 8,
                marginBottom: 2,
                transition: 'background 0.12s',
              }}
            >
              <MessageSquare size={14} strokeWidth={1.5} color="var(--sidebar-text-muted)" style={{ flexShrink: 0 }} />
              <span style={{
                flex: 1, fontSize: 13, color: 'var(--sidebar-text)',
                overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
              }}>
                {conv.title}
              </span>
              {(isHover || isActive) && (
                <button
                  onClick={(e) => { e.stopPropagation(); onDelete(conv.id); }}
                  style={{
                    background: 'none', border: 'none', cursor: 'pointer',
                    color: 'var(--sidebar-text-muted)', padding: 2,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    flexShrink: 0, borderRadius: 4, opacity: 0.7,
                  }}
                  title="Delete conversation"
                >
                  <Trash2 size={14} strokeWidth={1.8} />
                </button>
              )}
            </div>
          );
        })}
      </div>

      {/* Footer */}
      <div style={{
        padding: '12px 16px',
        borderTop: '1px solid var(--sidebar-border)',
        display: 'flex', alignItems: 'center', gap: 10,
        fontSize: 11, color: 'var(--sidebar-text-muted)',
      }}>
        <span style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
          <Dot on={health?.anthropic && health?.openai} />
          {health?.anthropic && health?.openai ? 'All systems online' : 'Setup needed'}
        </span>
      </div>
    </div>
  );
}

/* Toggle button when sidebar is collapsed (inline in top bar) */
export function SidebarToggle({ onClick }) {
  return (
    <button
      onClick={onClick}
      style={{
        width: 32, height: 32, borderRadius: 8,
        background: 'transparent', border: 'none',
        cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center',
        color: 'var(--ink-3)', flexShrink: 0,
      }}
      title="Open sidebar"
    >
      <PanelLeft size={18} strokeWidth={1.8} />
    </button>
  );
}
